"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[384168],{969370:e=>{e.exports=JSON.parse('{"tag":{"label":"networking","permalink":"/dst-api-webdocs/docs/tags/networking","allTagsPath":"/dst-api-webdocs/docs/tags","count":24,"items":[{"id":"game-scripts/components/attunable","title":"Attunable","description":"Manages persistent links between entities and players, enabling attunement mechanics for items like resurrection effigies.","permalink":"/dst-api-webdocs/docs/game-scripts/components/attunable"},{"id":"game-scripts/prefabs/balatro_util","title":"Balatro Util","description":"Provides shared constants, data encoding utilities, and light animation management for the Balatro minigame system.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/balatro_util"},{"id":"game-scripts/prefabs/boatrace_common","title":"Boatrace Common","description":"Provides utility functions and prefab factories for boat race events, including deploy helper visuals, throwable deploy kits, and placement validation logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boatrace_common"},{"id":"game-scripts/components/equippable","title":"Equippable","description":"Manages item equipping behavior, including slot assignment, unequip prevention, movement speed modifiers, dapperness, moisture, and equip/unequip callbacks for entities in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/components/equippable"},{"id":"game-scripts/prefabs/fan_wheel","title":"Fan Wheel","description":"A client-side FX prefab that visually represents a spinning fan wheel attached to an item, synchronized with networked spinning state and cleaned up via stategraph transitions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fan_wheel"},{"id":"game-scripts/components/follower","title":"Follower","description":"Manages an entity\'s relationship to a leader, including loyalty mechanics, teleportation on separation, and handling player reconnection or respawning.","permalink":"/dst-api-webdocs/docs/game-scripts/components/follower"},{"id":"game-scripts/components/giftreceiver","title":"Giftreceiver","description":"Manages the receiver side of gift items, tracking gift count and coordinating with gift machines.","permalink":"/dst-api-webdocs/docs/game-scripts/components/giftreceiver"},{"id":"game-scripts/components/inventoryitemmoisture","title":"Inventoryitemmoisture","description":"Manages moisture level and wet state for inventory items, synchronizing them with environmental conditions, owner state, or external control.","permalink":"/dst-api-webdocs/docs/game-scripts/components/inventoryitemmoisture"},{"id":"game-scripts/widgets/redux/mainmenu_motdpanel","title":"Mainmenu Motdpanel","description":"Renders the main menu\'s message-of-the-day panel, displaying announcements, update notes, and image-rich content with support for multiple panes, navigation bullets, and URL links.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/mainmenu_motdpanel"},{"id":"game-scripts/widgets/redux/modstab","title":"Modstab","description":"Manages the UI and logic for the mod management screen, including mod listing, filtering, enabling/disabling, dependency handling, and workshop updates.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/modstab"},{"id":"game-scripts/components/moonaltarlinktarget","title":"Moonaltarlinktarget","description":"Enables moon altars to detect and link with nearby altars of compatible types to form a valid triangle for cosmic events.","permalink":"/dst-api-webdocs/docs/game-scripts/components/moonaltarlinktarget"},{"id":"game-scripts/networkclientrpc","title":"Networkclientrpc","description":"This component defines comprehensive RPC handler tables for server, client, and shard contexts, including input validation helpers, queue processing logic, and utilities for managing mod-specific RPC registration and transmission states.","permalink":"/dst-api-webdocs/docs/game-scripts/networkclientrpc"},{"id":"game-scripts/components/nutrients_visual_manager","title":"Nutrients Visual Manager","description":"Manages visibility and rendering state of nutrient-related visual effects based on the player\'s nutrient vision toggle.","permalink":"/dst-api-webdocs/docs/game-scripts/components/nutrients_visual_manager"},{"id":"game-scripts/prefabs/piratewarningsound","title":"Piratewarningsound","description":"Creates a one-frame local sound effect for pirate-related warnings, positioned near the player and anchored to their current platform when applicable.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/piratewarningsound"},{"id":"game-scripts/prefabs/player_common_extensions","title":"Player Common Extensions","description":"Provides shared logic for player lifecycle management including death, resurrection, locomotion, actions, mini-map visibility, and commander/leader behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/player_common_extensions"},{"id":"game-scripts/components/playingcardsmanager","title":"Playingcardsmanager","description":"Manages the pool of available playing card IDs and handles the creation and lifecycle of playing card prefabs and decks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playingcardsmanager"},{"id":"game-scripts/components/saltlicker","title":"Saltlicker","description":"Manages the salt-licking behavior for entities, including detecting nearby saltlicks, applying timed salted states, and consuming uses from the saltlick.","permalink":"/dst-api-webdocs/docs/game-scripts/components/saltlicker"},{"id":"game-scripts/screens/servercreationscreen","title":"Servercreationscreen","description":"Manages the server creation and configuration UI, including save slot selection, tab navigation, game mode/world settings input, mod management, and server launch.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/servercreationscreen"},{"id":"game-scripts/screens/redux/serverlistingscreen","title":"Serverlistingscreen","description":"Manages the server browsing UI, including filtering, sorting, listing, and joining of online and LAN servers with dynamic filter management and server metadata display.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/serverlistingscreen"},{"id":"game-scripts/components/sharkboimanagerhelper","title":"Sharkboimanagerhelper","description":"Helper component for managing and querying the Sharkboi arena\u2019s spatial boundaries in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sharkboimanagerhelper"},{"id":"game-scripts/components/spectatorcorpse","title":"Spectatorcorpse","description":"Manages camera focus behavior for a player entity when spectating from a corpse, smoothly adjusting the camera range toward the nearest living player.","permalink":"/dst-api-webdocs/docs/game-scripts/components/spectatorcorpse"},{"id":"game-scripts/components/unevenground","title":"Unevenground","description":"Periodically notifies nearby players when they enter a zone affected by uneven ground, triggering related gameplay effects.","permalink":"/dst-api-webdocs/docs/game-scripts/components/unevenground"},{"id":"game-scripts/prefabs/wintersfeastfood","title":"Wintersfeastfood","description":"Generates 9 distinct seasonal food prefabs for the Winters Feast event, each with configurable nutrition, sanity, temperature, and visual floater properties.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wintersfeastfood"},{"id":"game-scripts/prefabs/wurt","title":"Wurt","description":"Implements the Wurt character\'s unique gameplay mechanics including pathfinding support, wetness-based skill interactions, and Merm King upgrades via debuff-based planar buffs for followers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wurt"}],"unlisted":false}}')}}]);